import { create } from 'zustand';

type UserRole = 'admin' | 'employee' | null;

interface AuthState {
  role: UserRole;
  isAuthenticated: boolean;
  email: string | null;
  faceRegistered: boolean;
  login: (role: UserRole, email: string) => void;
  setFaceRegistered: (status: boolean) => void;
  logout: () => void;
}

export const useAuthStore = create<AuthState>((set) => ({
  role: null,
  isAuthenticated: false,
  email: null,
  faceRegistered: false,
  login: (role, email) => set({ role, isAuthenticated: true, email }),
  setFaceRegistered: (status) => set({ faceRegistered: status }),
  logout: () => set({ role: null, isAuthenticated: false, email: null, faceRegistered: false }),
}));
